**Why This Is Dangerous**:
- MFA code is not bound to a specific login attempt, device, or IP, so any attacker with the email can guess codes.
- No expiration, no retry limits, and a small 6-digit numeric space make brute-force practical.
- MFA codes are reusable and not invalidated after success, enabling replay attacks if intercepted.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import rateLimit from 'express-rate-limit';

const app = express();
app.use(express.json());

interface User {
  passwordHash: string;
  phone: string;
}

// Demo users; in production, use a real DB and a secure password hash (e.g. argon2)
const users: Record<string, User> = {
  'alice@example.com': {
    passwordHash: 'Password123!',
    phone: '+15550001111'
  }
};

interface PendingMfa {
  email: string;
  codeHash: string;
  expiresAt: number;
  attempts: number;
  ip: string;
}

// Store pending MFA challenges keyed by a temporary MFA token
const pendingMfaChallenges: Map<string, PendingMfa> = new Map();

function hashCode(code: string): string {
  return crypto.createHash('sha256').update(code).digest('hex');
}

function generateNumericCode(length: number = 8): string {
  // More entropy than 6 digits, but still user-friendly
  const max = 10 ** length;
  const num = crypto.randomInt(0, max);
  return num.toString().padStart(length, '0');
}

function sendSms(phone: string, message: string): void {
  // Placeholder: integrate with a real provider like Twilio in production
  console.log(`SMS to ${phone}: ${message}`);
}

const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 20,
  standardHeaders: true,
  legacyHeaders: false
});

const mfaLimiter = rateLimit({
  windowMs: 10 * 60 * 1000,
  max: 30,
  standardHeaders: true,
  legacyHeaders: false
});

function asyncHandler(fn: (req: Request, res: Response, next: NextFunction) => Promise<void> | void) {
  return (req: Request, res: Response, next: NextFunction) => {
    Promise.resolve(fn(req, res, next)).catch(next);
  };
}

app.post('/login', loginLimiter, asyncHandler(async (req: Request, res: Response) => {
  const { email, password } = req.body;

  if (typeof email !== 'string' || typeof password !== 'string') {
    return res.status(400).json({ error: 'Invalid payload' });
  }

  const user = users[email];
  if (!user || user.passwordHash !== password) {
    console.warn(`Failed login for ${email} from ${req.ip}`);
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  const code = generateNumericCode(8); // 8-digit code
  const codeHash = hashCode(code);

  // Token that identifies this MFA challenge, not the final session
  const mfaToken = crypto.randomBytes(32).toString('hex');

  pendingMfaChallenges.set(mfaToken, {
    email,
    codeHash,
    expiresAt: Date.now() + 5 * 60 * 1000, // 5 minutes expiry
    attempts: 0,
    ip: req.ip
  });

  sendSms(user.phone, `Your login verification code is: ${code}`);

  console.info(`MFA challenge created for ${email} from ${req.ip}`);

  return res.json({
    message: 'MFA code sent. Please verify.',
    mfaToken
  });
}));

app.post('/login/mfa-verify', mfaLimiter, asyncHandler(async (req: Request, res: Response) => {
  const { mfaToken, code } = req.body;

  if (typeof mfaToken !== 'string' || typeof code !== 'string') {
    return res.status(400).json({ error: 'Invalid payload' });
  }

  const challenge = pendingMfaChallenges.get(mfaToken);

  if (!challenge) {
    console.warn(`Unknown or reused MFA token from ${req.ip}`);
    return res.status(401).json({ error: 'Invalid or expired code' });
  }

  if (challenge.ip !== req.ip) {
    console.warn(`MFA IP mismatch for ${challenge.email}: expected ${challenge.ip}, got ${req.ip}`);
    pendingMfaChallenges.delete(mfaToken);
    return res.status(401).json({ error: 'Invalid or expired code' });
  }

  if (Date.now() > challenge.expiresAt) {
    console.warn(`Expired MFA code for ${challenge.email}`);
    pendingMfaChallenges.delete(mfaToken);
    return res.status(401).json({ error: 'Invalid or expired code' });
  }

  if (challenge.attempts >= 5) {
    console.warn(`Too many MFA attempts for ${challenge.email}`);
    pendingMfaChallenges.delete(mfaToken);
    return res.status(429).json({ error: 'Too many attempts' });
  }

  challenge.attempts += 1;

  if (hashCode(code) !== challenge.codeHash) {
    console.warn(`Invalid MFA code for ${challenge.email} from ${req.ip}`);
    return res.status(401).json({ error: 'Invalid or expired code' });
  }

  // Success: remove challenge to prevent reuse
  pendingMfaChallenges.delete(mfaToken);

  const sessionToken = crypto.randomBytes(32).toString('hex');
  console.info(`Successful MFA login for ${challenge.email} from ${req.ip}`);

  return res.json({ token: sessionToken });
}));

app.use((err: any, req: Request, res: Response, _next: NextFunction) => {
  console.error('Unexpected error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(3000, () => {
  console.log('Secure MFA server running on port 3000');
});
```

**Key Security Controls**:
- Strong MFA challenge management: codes are hashed, time-limited, single-use, and tracked with attempt counters to mitigate brute-force and replay.
- Context binding and rate limiting: MFA challenges are bound to the originating IP and constrained by per-endpoint rate limits to reduce MFA fatigue and guessing attacks.
- Secure error handling and logging: generic responses avoid leaking information, while structured logging supports detection of suspicious MFA patterns.

In production, you want a flexible MFA framework that supports multiple strong factors (TOTP, WebAuthn, backup codes), context-aware risk checks, and robust logging/monitoring.

