    return res.status(401).json({ error: 'Invalid or expired challenge' });
  }

  const user = usersById.get(challenge.userId);
  if (!user) {
    mfaChallenges.delete(challengeId);
    return res.status(401).json({ error: 'Invalid challenge' });
  }

  // Defense against MFA fatigue: enforce IP and device consistency
  if (challenge.ip !== req.ip) {
    console.warn(`MFA IP mismatch for ${user.email}: expected ${challenge.ip}, got ${req.ip}`);
    mfaChallenges.delete(challengeId);
    return res.status(401).json({ error: 'Invalid or expired challenge' });
  }

