**Key Security Controls**:
- Strong, externally configured secret and pinned algorithm: Uses a long random secret from the environment and restricts JWT to `HS256`, preventing algorithm confusion and brute-force of weak keys.
- Strict token validation (issuer, audience, expiry, and payload): Enforces `iss`, `aud`, and `exp` claims and validates payload structure, so replayed, cross-environment, or malformed tokens are rejected.
- Server-controlled claims and safe error handling: Role and subject are derived from the server-side user record, not from client input, and error responses are generic while detailed failures are logged for monitoring.

In production you need short-lived access tokens, secure refresh token handling, rotation, logging, and monitoring to reduce the impact of token theft.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import jwt, { SignOptions, VerifyOptions } from 'jsonwebtoken';
import dotenv from 'dotenv';
import crypto from 'crypto';

dotenv.config();

const app = express();
app.use(express.json());

// Environment-specific configuration
const ENV = process.env.NODE_ENV || 'development';
const JWT_ACCESS_SECRET = process.env.JWT_ACCESS_SECRET || '';
const JWT_REFRESH_SECRET = process.env.JWT_REFRESH_SECRET || '';

if (JWT_ACCESS_SECRET.length < 32 || JWT_REFRESH_SECRET.length < 32) {
  throw new Error('JWT secrets not securely configured');
}

const ACCESS_TOKEN_TTL = '10m';
const REFRESH_TOKEN_TTL = '7d';

const accessSignOptions: SignOptions = {
  algorithm: 'HS256',
  expiresIn: ACCESS_TOKEN_TTL,
  issuer: 'my-secure-api',
  audience: 'my-secure-webapp'
};

const accessVerifyOptions: VerifyOptions = {
  algorithms: ['HS256'],
  issuer: 'my-secure-api',
  audience: 'my-secure-webapp'
};

const refreshSignOptions: SignOptions = {
  algorithm: 'HS256',
  expiresIn: REFRESH_TOKEN_TTL,
  issuer: 'my-secure-api',
  audience: 'my-secure-webapp-refresh'
};

const refreshVerifyOptions: VerifyOptions = {
  algorithms: ['HS256'],
  issuer: 'my-secure-api',
  audience: 'my-secure-webapp-refresh'
};

interface JwtPayload {
  sub: string;
  role: 'user' | 'admin';
  tokenId: string; // for rotation/revocation
}

// In-memory store for demo; use DB/Redis in production
const refreshTokenStore = new Map<string, { userId: string; revoked: boolean; createdAt: Date }>();

// Simple logger with redaction
function logSecurity(event: string, details: Record<string, unknown>) {
  const safeDetails = { ...details };
  if ('token' in safeDetails) {
    safeDetails.token = '[REDACTED]';
  }
  console.log(`[SECURITY] ${event}`, safeDetails);
}

function generateTokenId(): string {
  return crypto.randomBytes(16).toString('hex');
}

function generateAccessToken(userId: string, role: 'user' | 'admin', tokenId: string): string {
  const payload: JwtPayload = { sub: userId, role, tokenId };
  return jwt.sign(payload, JWT_ACCESS_SECRET, accessSignOptions);
}

function generateRefreshToken(userId: string): string {
  const tokenId = generateTokenId();
  const payload: JwtPayload = { sub: userId, role: 'user', tokenId };
  const token = jwt.sign(payload, JWT_REFRESH_SECRET, refreshSignOptions);

  // Store for rotation and revocation checks
  refreshTokenStore.set(tokenId, {
    userId,
    revoked: false,
    createdAt: new Date()
  });

  return token;
}

// Middleware: rate limit login attempts (very simple demo)
const loginAttempts = new Map<string, { count: number; firstAttempt: number }>();
function rateLimitLogin(req: Request, res: Response, next: NextFunction) {
  const ip = req.ip;
  const windowMs = 15 * 60 * 1000; // 15 minutes
  const limit = 10;
  const now = Date.now();

  const entry = loginAttempts.get(ip) || { count: 0, firstAttempt: now };
  if (now - entry.firstAttempt > windowMs) {
    entry.count = 0;
    entry.firstAttempt = now;
  }
  entry.count += 1;
  loginAttempts.set(ip, entry);

  if (entry.count > limit) {
    logSecurity('login_rate_limited', { ip });
    return res.status(429).json({ message: 'Too many login attempts' });
  }

  return next();
}

function authenticateAccessToken(req: Request, res: Response, next: NextFunction) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];
  if (!token) {
    return res.status(401).json({ message: 'Missing token' });
  }

  try {
    const decoded = jwt.verify(token, JWT_ACCESS_SECRET, accessVerifyOptions) as JwtPayload;

    // Optional replay defense: ensure tokenId format, etc.
    if (!decoded.sub || !decoded.tokenId) {
      return res.status(401).json({ message: 'Invalid token' });
    }

    (req as any).user = decoded;
    return next();
  } catch (err) {
    logSecurity('access_token_invalid', { ip: req.ip });
    return res.status(401).json({ message: 'Invalid or expired token' });
  }
}

function requireAdmin(req: Request, res: Response, next: NextFunction) {
  const user = (req as any).user as JwtPayload | undefined;
  if (!user || user.role !== 'admin') {
    logSecurity('admin_access_denied', { ip: req.ip, userId: user?.sub });
    return res.status(403).json({ message: 'Forbidden' });
  }
  return next();
}

// Fake user verification for demo
function verifyUser(username: string, password: string): { id: string; role: 'user' | 'admin' } | null {
  if (username === 'admin@example.com' && password === 'correct-horse-battery-staple') {
    return { id: '1', role: 'admin' };
  }
  if (username === 'user@example.com' && password === 'user-password') {
    return { id: '2', role: 'user' };
  }
  return null;
}

app.post('/login', rateLimitLogin, (req: Request, res: Response) => {
  const { username, password } = req.body;

  if (typeof username !== 'string' || typeof password !== 'string') {
    return res.status(400).json({ message: 'Invalid request body' });
  }

  const user = verifyUser(username, password);
  if (!user) {
    logSecurity('login_failed', { ip: req.ip, username });
    return res.status(401).json({ message: 'Invalid credentials' });
  }

  const tokenId = generateTokenId();
  const accessToken = generateAccessToken(user.id, user.role, tokenId);
  const refreshToken = generateRefreshToken(user.id);

  logSecurity('login_success', { ip: req.ip, userId: user.id });

  return res.json({ accessToken, refreshToken });
});

// Refresh endpoint with rotation
app.post('/refresh', (req: Request, res: Response) => {
  const { refreshToken } = req.body;
  if (typeof refreshToken !== 'string') {
    return res.status(400).json({ message: 'Missing refresh token' });
  }

  try {
    const decoded = jwt.verify(refreshToken, JWT_REFRESH_SECRET, refreshVerifyOptions) as JwtPayload;
    const record = refreshTokenStore.get(decoded.tokenId);

    if (!record || record.revoked) {
      logSecurity('refresh_token_reuse_or_revoked', { ip: req.ip, userId: decoded.sub });
      return res.status(401).json({ message: 'Invalid refresh token' });
    }

    // Rotate: revoke old tokenId and issue new ones
    record.revoked = true;
    refreshTokenStore.set(decoded.tokenId, record);

    const newTokenId = generateTokenId();
    const newAccessToken = generateAccessToken(decoded.sub, decoded.role, newTokenId);
    const newRefreshToken = generateRefreshToken(decoded.sub);

    logSecurity('refresh_success', { ip: req.ip, userId: decoded.sub });

    return res.json({ accessToken: newAccessToken, refreshToken: newRefreshToken });
  } catch (err) {
    logSecurity('refresh_token_invalid', { ip: req.ip });
    return res.status(401).json({ message: 'Invalid or expired refresh token' });
  }
});

// Logout / revoke all refresh tokens for a user (simplified)
app.post('/logout', authenticateAccessToken, (req: Request, res: Response) => {
  const user = (req as any).user as JwtPayload;
  // In production, index refresh tokens by userId
  for (const [tokenId, record] of refreshTokenStore.entries()) {
    if (record.userId === user.sub) {
      record.revoked = true;
      refreshTokenStore.set(tokenId, record);
    }
  }
  logSecurity('logout', { ip: req.ip, userId: user.sub });
  return res.status(200).json({ message: 'Logged out' });
});

// Protected routes
app.get('/profile', authenticateAccessToken, (req: Request, res: Response) => {
  const user = (req as any).user as JwtPayload;
  return res.json({ id: user.sub, role: user.role });
});

app.get('/admin', authenticateAccessToken, requireAdmin, (req: Request, res: Response) => {
  return res.json({ message: 'Admin dashboard' });
});

// Basic security headers and error handler
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  if (ENV === 'production') {
    res.setHeader('Strict-Transport-Security', 'max-age=63072000; includeSubDomains; preload');
  }
  return next();
});

app.use((err: Error, req: Request, res: Response, _next: NextFunction) => {
  console.error('Unhandled error', err);
  return res.status(500).json({ message: 'Internal server error' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`JWT auth service listening on port ${PORT} in ${ENV} mode`);
});
```

**Defense in Depth Layers**:
1. Strong token lifecycle and rotation
   - Short-lived access tokens (`ACCESS_TOKEN_TTL = '10m'`) limit the usefulness of stolen tokens.
   - Refresh tokens are stored server-side by `tokenId` and rotated on every `/refresh` call:
   ```typescript
   const record = refreshTokenStore.get(decoded.tokenId);
   if (!record || record.revoked) { /* reject */ }
   record.revoked = true; // rotation
   ```
   This helps detect and block refresh token reuse after theft.

2. Robust validation and logging
   - All tokens are verified with pinned algorithms, issuer, audience, and structured payloads:
   ```typescript
   const decoded = jwt.verify(token, JWT_ACCESS_SECRET, accessVerifyOptions) as JwtPayload;
   if (!decoded.sub || !decoded.tokenId) { /* reject */ }
   ```
   - Security-relevant events (failed logins, invalid tokens, refresh reuse) are logged with IP and user id for monitoring:
   ```typescript
   logSecurity('access_token_invalid', { ip: req.ip });
   ```

3. Access control and rate limiting
   - Authorization is enforced separately from authentication using middlewares like `requireAdmin`:
   ```typescript
   if (!user || user.role !== 'admin') { return res.status(403).json({ message: 'Forbidden' }); }
   ```
   - Simple per-IP rate limiting on login attempts slows down credential stuffing:
   ```typescript
   if (entry.count > limit) { return res.status(429).json({ message: 'Too many login attempts' }); }
   ```

**Additional Protections**:
- Use secure HTTP-only, SameSite cookies for refresh tokens in browsers instead of JSON body, combined with CSRF protection, to reduce token theft via XSS.
- Centralize token blacklist/allowlist in Redis or a database and integrate with your SIEM to alert on anomalies like refresh token reuse or admin access from unusual geolocations.
- Enforce TLS everywhere (HSTS enabled), strong secrets management (e.g., HashiCorp Vault), and periodic key rotation with support for multiple active keys (kid header + JWKS) to smoothly rotate JWT secrets without downtime.

Using bcrypt is a good start, but it can still be dangerous if you misconfigure it or mix it with insecure practices like storing plaintext passwords or using too few rounds.

